```java
import java.util.ArrayList;
import java.util.List;

public class Main {

    public static void main(String[] args) {
        int num = 113;
        System.out.println(PrimeChecker(num)); // Output: 1
    }

    public static int PrimeChecker(int num) {
        String strNum = Integer.toString(num);
        List<Integer> permutations = new ArrayList<>();

        generatePermutations(strNum.toCharArray(), 0, permutations);

        for (int perm : permutations) {
            if (isPrime(perm)) {
                return 1;
            }
        }

        return 0;
    }

    private static void generatePermutations(char[] arr, int index, List<Integer> permutations) {
        if (index == arr.length - 1) {
            permutations.add(Integer.parseInt(new String(arr)));
        }

        for (int i = index; i < arr.length; i++) {
            swap(arr, index, i);
            generatePermutations(arr, index + 1, permutations);
            swap(arr, index, i);
        }
    }

    private static void swap(char[] arr, int i, int j) {
        char temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }

    private static boolean isPrime(int num) {
        if (num <= 1) {
            return false;
        }

        for (int i = 2; i <= Math.sqrt(num); i++) {
            if (num % i == 0) {
                return false;
            }
        }

        return true;
    }
}
```

